import{_ as o,o as i,c as a,a6 as n}from"./chunks/framework.B6HGZFrS.js";const p=JSON.parse('{"title":"Branching and Merge Rules","description":"","frontmatter":{},"headers":[],"relativePath":"agent-instructions/branching.md","filePath":"agent-instructions/branching.md","lastUpdated":1781100822000}'),r={name:"agent-instructions/branching.md"};function l(c,e,t,d,s,h){return i(),a("div",null,[...e[0]||(e[0]=[n('<h1 id="branching-and-merge-rules" tabindex="-1">Branching and Merge Rules <a class="header-anchor" href="#branching-and-merge-rules" aria-label="Permalink to “Branching and Merge Rules”">​</a></h1><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to “Overview”">​</a></h2><p>Use this file when creating branches, opening pull requests, or deciding how <code>dev</code> and <code>main</code> should move.</p><h2 id="branch-roles" tabindex="-1">Branch Roles <a class="header-anchor" href="#branch-roles" aria-label="Permalink to “Branch Roles”">​</a></h2><ul><li><code>dev</code> is the integration branch for active development.</li><li><code>main</code> is the stable release branch.</li><li>Feature, fix, refactor, test, and docs work must start from <code>dev</code>.</li><li>Ordinary development work should not open pull requests directly into <code>main</code>.</li></ul><h2 id="development-flow" tabindex="-1">Development Flow <a class="header-anchor" href="#development-flow" aria-label="Permalink to “Development Flow”">​</a></h2><ol><li>Sync local <code>dev</code> from <code>origin/dev</code>.</li><li>Create a topic branch from <code>dev</code>.</li><li>Use a project-scoped branch name such as <code>feat/...</code>, <code>fix/...</code>, <code>refactor/...</code>, <code>docs/...</code>, <code>test/...</code>, <code>chore/...</code>, or <code>sync/...</code>.</li><li>Implement and validate the change on the topic branch.</li><li>Open a pull request back into <code>dev</code>.</li><li>Confirm the <code>Dev Version Line</code> check passes; it verifies the PR result uses the same <code>&lt;manual&gt;.&lt;main&gt;</code> version line as <code>origin/main</code>.</li><li>Merge into <code>dev</code> only after the expected checks and review pass.</li></ol><h2 id="promoting-dev-to-main" tabindex="-1">Promoting Dev to Main <a class="header-anchor" href="#promoting-dev-to-main" aria-label="Permalink to “Promoting Dev to Main”">​</a></h2><p>When <code>dev</code> is stable, promote it through a pull request into <code>main</code>.</p><p>Default flow:</p><ol><li>Sync <code>origin/dev</code> and <code>origin/main</code>.</li><li>Open a pull request from <code>dev</code> into <code>main</code>.</li><li>Confirm GitHub reports the pull request as mergeable.</li><li>Run or wait for the required checks.</li><li>Merge the pull request into <code>main</code>.</li></ol><p>Use this direct <code>dev -&gt; main</code> pull request whenever it is clean and mergeable.</p><h2 id="conflict-flow" tabindex="-1">Conflict Flow <a class="header-anchor" href="#conflict-flow" aria-label="Permalink to “Conflict Flow”">​</a></h2><p>Use a temporary sync branch only when <code>dev -&gt; main</code> cannot be merged cleanly or needs manual conflict resolution.</p><ol><li>Sync <code>origin/main</code> and <code>origin/dev</code>.</li><li>Create a sync branch from <code>origin/main</code>, for example <code>sync/dev-to-main</code>.</li><li>Merge <code>origin/dev</code> into the sync branch.</li><li>Resolve conflicts intentionally.</li><li>Run required validation.</li><li>Open a pull request from the sync branch into <code>main</code>.</li></ol><p>This is an exception path for conflicts, not the default release path.</p><h2 id="after-main-changes" tabindex="-1">After Main Changes <a class="header-anchor" href="#after-main-changes" aria-label="Permalink to “After Main Changes”">​</a></h2><p>If <code>main</code> receives changes that are not already in <code>dev</code>, bring them back to <code>dev</code>.</p><p>Common examples:</p><ul><li>version bumps</li><li><code>CHANGELOG.md</code> updates</li><li>release workflow outputs</li><li>stable-branch hotfixes</li><li>conflict-resolution fixes made during a <code>dev -&gt; main</code> promotion</li></ul><p>Use a small sync branch from <code>dev</code> and open a pull request back into <code>dev</code> when needed.</p><p>If a pull request into <code>dev</code> fails the <code>Dev Version Line</code> check, sync the main release version metadata back into <code>dev</code> before merging new feature work.</p><h2 id="conflict-resolution-policy" tabindex="-1">Conflict Resolution Policy <a class="header-anchor" href="#conflict-resolution-policy" aria-label="Permalink to “Conflict Resolution Policy”">​</a></h2><ul><li>Preserve <code>main</code> release metadata when promoting to <code>main</code>, including version bumps, <code>CHANGELOG.md</code>, and release workflow outputs.</li><li>Preserve ESM/CJS package-entry fixes unless the replacement is a verified superset.</li><li>Preserve <code>dev</code> feature implementation when promoting stable work, including CLI, framework, route, and test improvements.</li><li>Do not downgrade <code>package.json</code> or <code>package-lock.json</code> versions during promotion.</li><li>Do not commit regenerated <code>docs/public/version.json</code> unless the task is explicitly a version or release update.</li><li>For package-entry changes, verify both ESM import and CJS require behavior with package-entry tests.</li></ul><h2 id="hotfixes" tabindex="-1">Hotfixes <a class="header-anchor" href="#hotfixes" aria-label="Permalink to “Hotfixes”">​</a></h2><p>Emergency fixes may branch from <code>main</code> only when the user explicitly asks for a stable-branch hotfix. After merging a hotfix into <code>main</code>, backport or merge it into <code>dev</code> so future development does not lose the fix.</p><h2 id="validation" tabindex="-1">Validation <a class="header-anchor" href="#validation" aria-label="Permalink to “Validation”">​</a></h2><p>Before opening a release or sync pull request, run:</p><ul><li><code>npm run build</code></li><li><code>npm run test</code></li><li><code>npm run lint</code></li><li><code>npm run docs:build</code> when docs changed</li></ul>',29)])])}const u=o(r,[["render",l]]);export{p as __pageData,u as default};
